import { Hound, HoundManagement } from 'hound/';

const hound = Hound.create({ db: redis });
const mgmt = new HoundManagement({ db: redis, hound });

// Find all failed jobs in the emails queue
const failed = await mgmt.api.jobs.find({ queue: 'emails', status: 'failed' });

// Retry each one
for (const job of failed) {
  await mgmt.api.jobs.retry(`${job.queue}:${job.id}`);
}

const stats = await mgmt.api.queues.stats('emails');
console.log(stats);
// { waiting: 12, delayed: 3, processing: 2, completed: 840, failed: 1, total: 858 }

// Subscribe to all terminal events
const off = mgmt.events.job.finished((payload) => {
  console.log(payload.jobId, payload.status);
});

// Subscribe to failures only
mgmt.events.job.failed((payload) => {
  alertTeam(`Job ${payload.jobId} failed: ${payload.error}`);
});

// Unsubscribe later
off();
